import React from "react";
import {
  Box,
  Flex,
  Grid,
  Text,
  Stat,
  StatLabel,
  StatNumber,
  Icon,
} from "@chakra-ui/react";
import { FaBook, FaUsers } from "react-icons/fa";
import TeacherNavTop from "./TeacherNavTop";

const TeacherDashboard = () => {
  // Dummy data
  const courses = [
    { id: 1, title: "Course A", enrolledUsers: 20 },
    { id: 2, title: "Course B", enrolledUsers: 15 },
    { id: 3, title: "Course C", enrolledUsers: 30 },
  ];

  // Stats
  const totalCourses = courses.length;
  const totalStudents = courses.reduce(
    (acc, cur) => acc + cur.enrolledUsers,
    0
  );

  return (
    <Box bg="#f7f9fa" minH="100vh">
      <TeacherNavTop />

      <Box maxW="1200px" mx="auto" mt="100px" px={4}>
        {/* HEADER */}
        <Text fontSize="2xl" fontWeight="bold" mb={6}>
          Instructor Dashboard
        </Text>

        {/* STATS */}
        <Grid
          templateColumns={{
            base: "1fr",
            md: "repeat(2,1fr)",
          }}
          gap={6}
          mb={8}
        >
          {/* Total Courses */}
          <Box
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="lg"
            _hover={{ transform: "translateY(-3px)", boxShadow: "xl" }}
            transition="0.2s"
          >
            <Flex align="center" justify="space-between">
              <Stat>
                <StatLabel>Total Courses</StatLabel>
                <StatNumber>{totalCourses}</StatNumber>
              </Stat>
              <Icon as={FaBook} boxSize={8} color="#A435F0" />
            </Flex>
          </Box>

          {/* Total Students */}
          <Box
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="lg"
            _hover={{ transform: "translateY(-3px)", boxShadow: "xl" }}
            transition="0.2s"
          >
            <Flex align="center" justify="space-between">
              <Stat>
                <StatLabel>Total Students</StatLabel>
                <StatNumber>{totalStudents}</StatNumber>
              </Stat>
              <Icon as={FaUsers} boxSize={8} color="#A435F0" />
            </Flex>
          </Box>
        </Grid>

        {/* COURSE LIST */}
        <Text fontSize="xl" fontWeight="bold" mb={4}>
          Your Courses
        </Text>

        <Grid
          templateColumns={{
            base: "1fr",
            md: "repeat(2,1fr)",
            lg: "repeat(3,1fr)",
          }}
          gap={6}
        >
          {courses.map((course) => (
            <Box
              key={course.id}
              bg="white"
              p={5}
              borderRadius="lg"
              boxShadow="lg"
              _hover={{
                transform: "translateY(-5px)",
                boxShadow: "xl",
              }}
              transition="0.2s"
              cursor="pointer"
            >
              <Text fontWeight="bold" fontSize="lg" mb={2}>
                {course.title}
              </Text>

              <Text color="gray.600">
                {course.enrolledUsers} students enrolled
              </Text>
            </Box>
          ))}
        </Grid>

        {/* PLACEHOLDER CHARTS */}
        <Grid
          mt={10}
          templateColumns={{
            base: "1fr",
            lg: "repeat(2,1fr)",
          }}
          gap={6}
        >
          <Box
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="lg"
            h="300px"
          >
            <Text fontWeight="bold" mb={2}>
              Revenue / Students Chart
            </Text>
            <Text color="gray.500">
              (Add chart here later)
            </Text>
          </Box>

          <Box
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="lg"
            h="300px"
          >
            <Text fontWeight="bold" mb={2}>
              Course Distribution
            </Text>
            <Text color="gray.500">
              (Add pie chart here later)
            </Text>
          </Box>
        </Grid>
      </Box>
    </Box>
  );
};

export default TeacherDashboard;
